module tiny_dtl_gate (
    input  wire ai_output,
    input  wire verifier_ok,
    input  wire policy_ok,
    input  wire sensor_ok,
    input  wire timeout,
    input  wire kill_switch,
    input  wire reset,
    output wire actuator_enable,
    output wire blocked,
    output wire failsafe,
    output wire approved,
    output wire evidence_pulse
);

    // Core DTL safety gate logic
    assign actuator_enable = ai_output && verifier_ok && policy_ok && sensor_ok && !timeout && !kill_switch && !reset;

    // Status outputs
    assign blocked = kill_switch || timeout || !verifier_ok || !policy_ok || !sensor_ok;
    assign failsafe = !actuator_enable;
    assign approved = actuator_enable;
    assign evidence_pulse = actuator_enable;

endmodule